import './App.css'

import { Button, Container, Box, makeStyles, Typography, Link, CardMedia, Card, CardActionArea } from '@material-ui/core'
import Grid from '@material-ui/core/Grid'
import '@fontsource/roboto'
import { useMediaQuery } from 'react-responsive'


import Contact from './components/Contact.js'

function App() {

  const isDesktop = useMediaQuery({ minWidth: 992 })

  const desktopStyles = makeStyles({
    profileImg: {
      maxWidth: 200,
      borderRadius: '50%'
    },
    media: {
      height: 0,
      paddingTop: "100%"
    },
    introBox: {
      marginTop: 360,
      marginBottom: 360
    },
  });

  const mobileStyles = makeStyles({
    profileImg: {
      borderRadius: '50%',
    },
    media: {
      minWidth: 200,
      paddingTop: "100%"
    },
    gridItems: {
      marginBlock: 20
    },
    gridItemsImage: {
      marginBlock: 20,
      minWidth: 200,
      margin: "auto"
    },
    introBox: {
      marginInline: 40,
      marginTop: 108
    },
  });

  const useStyles = isDesktop ? desktopStyles : mobileStyles;
  const classes = useStyles();

  const isTestMode = false;

  if (isTestMode) {
    const Desktop = ({ children }) => {
      const isDesktop = useMediaQuery({ minWidth: 992 })
      return isDesktop ? children : null
    }
    const Tablet = ({ children }) => {
      const isTablet = useMediaQuery({ minWidth: 768, maxWidth: 991 })
      return isTablet ? children : null
    }
    const Mobile = ({ children }) => {
      const isMobile = useMediaQuery({ maxWidth: 767 })
      return isMobile ? children : null
    }
    const Default = ({ children }) => {
      const isNotMobile = useMediaQuery({ minWidth: 768 })
      return isNotMobile ? children : null
    }
    
    const Example = () => (
      <div>
        <Desktop>Desktop or laptop</Desktop>
        <Tablet>Tablet</Tablet>
        <Mobile>Mobile</Mobile>
        <Default>Not mobile (desktop or laptop or tablet)</Default>
      </div>
    )
  }
  



  return (
    <div className="App">

      {/* NAVIGATION BAR */}
      <Box
        position="fixed" zIndex="1"
        width="100%" top="0" left="0"
        bgcolor="white">
      <Container className="header" maxWidth='lg'>
      <Box mt={4} mb={5}>
      <Grid container justify={isDesktop?"flex-end":"space-evenly"}>
        <Grid item>
          <a href="#" style={{textDecoration:"none"}}>
            <Button color="primary">
              About Me
            </Button>
          </a>
        </Grid>
        <Grid item>
          <a href="#" style={{textDecoration:"none"}}>
            <Button color="primary">
              Projects
            </Button>
          </a>
        </Grid>
        <Grid item>
          <a href="#contact" style={{textDecoration:"none"}}>
            <Button color="primary">
              Contact
            </Button>
          </a>
        </Grid>
      </Grid>
      </Box>
      </Container>
      </Box>
      
      {/* FIRST SECTION */}
      <Container className="intro" maxWidth="lg">
        <Box className={classes.introBox}>
          <Grid container
            direction={isDesktop ? "row" : "column"}
            justify="space-around"
            alignItems={isDesktop ? "flex-end" : "flex-start"}
          >
            {/* TODO: Align image to center of Grid item */}
            <Grid item xs={3} className={classes.gridItemsImage}>
              <Card className={classes.profileImg}>
                <CardMedia
                  className={classes.media}
                  image="/face_img.jpg"
                  title="Hi, I'm Ervin!"
                />
              </Card>
            </Grid>

            <Grid item xs={isDesktop ? 4 : 12} className={classes.gridItems}>
              <Typography variant="h2" align="left" gutterBottom>
                Hi,
              </Typography>
              <Typography align="left" gutterBottom>
                Welcome to the site where you get to know a little bit more about me.
                <br/>–<br/>
                My name is Ervin and I'm currently a third year student studying Computer Science in National Tsing Hua University.
              </Typography>
            </Grid>

            <Grid item xs={isDesktop ? 3 : 12} className={classes.gridItems}>
              <Typography align="left" gutterBottom>
                On this page you get to see the things I've learnt and the projects I've made.
                <br/>–<br/>
                You also get to know a little about my personality and my interests outside of tech.
              </Typography>
            </Grid>
          </Grid>
        </Box>

      </Container>

      {/* CONTACT */}
      {/* TODO: change style to proper styling using className */}
      <div id="contact" style={{marginInline:40}}>
        <Contact/>
      </div>
      
      {isTestMode ? <Example/> : null}

    </div>
  );
}

export default App;
